195	      customTooltip: CustomTooltipComponent,
196	      customTotalCount: CustomTotalCountComponent,
197	      datePicker: rfqDatepickerComponent,
198	      imageEditor: imageComponent,
199	      itemThumbnail: ItemThumbnailComponent,
200	      numericCellEditor: NumericEditor,
201	      propertyCell: PropertyCellComponent,
202	      statusPill: StatusPillComponent,
203	    };
204	
205	    // Set default column definitions FIRST
206	    this.defaultColDef = {
207	      resizable: true,
208	      sortable: true,
209	      filter: 'agTextColumnFilter',
210	      floatingFilter: true,
211	      editable: true,
212	      pivot: false,
