222	      getCurrentUserDisplayName,
223	    );
224	
225	    // NOW set grid options with the defined defaultColDef
226	    this.gridOptions = {
227	      rowModelType: 'serverSide',
228	      popupParent: document.body,
229	      defaultColDef: this.defaultColDef, // This is now defined
230	      detailRowAutoHeight: false,
231	      cellSelection: true,
232	      pagination: true,
233	      paginationPageSize: 100,
234	      paginationPageSizeSelector: [100, 200, 500, 1000],
235	      cacheBlockSize: 100,
236	      maxBlocksInCache: 10,
237	      blockLoadDebounceMillis: 500,
238	      animateRows: true,
239	      loading: true,
240	      suppressLoadingOverlay: true,
241	      tooltipShowDelay: 100,
242	      tooltipShowMode: "whenTruncated",
243	      components: this.frameworkComponents,
244	      detailCellRenderer: this.customDetailCellRenderer,
245	      getRowHeight: this.getRowHeight,
246	      sideBar: this.sideBar,
247	      enableFilterHandlers: true,
248	      getRowId: (params: GetRowIdParams) => String(params.data.id),
249	      notesDataSource: this.itemLibraryCellNotes.dataSource,
250	      context: {
251	        router: this.router,
252	        dialog: this.dialog,
253	        snackBar: this._snackBar,
254	        itemService: this.itemService,
255	        itemLibraryService: this.ItemLibraryService,
256	        togglePageToolbar: this.toggleToolbarVisibility.bind(this),
257	        currentUrl: this.currentUrl,
258	        phases: {
259	          pop: null,
260	          licensor: null
261	        },
262	        role: this.role,
263	        loaderService: this.loaderService,
264	        onItemThumbnailMouseEnter: (data: any, node: RowNode) => this.showThumbnailPreview(data, node),
265	        onItemThumbnailMouseLeave: () => this.hideThumbnailPreview()
266	      },
267	      statusBar: {
268	        statusPanels: [
269	          { statusPanel: 'agTotalRowCountComponent', align: 'center' },
270	          { statusPanel: 'agFilteredRowCountComponent' },
271	          { statusPanel: 'agSelectedRowCountComponent' },
272	          { statusPanel: 'agAggregationComponent' }
273	        ]
274	      },
275	      onRowClicked: (event) => {
276	        if (this.layout === 'split' && event.data) {
277	          this.activeItem = event.data;
278	          this.activeItemImgSrc = event.data.pic?.Thumbnail
279	            ? this.helperService.buildPublicUrl(event.data.pic.Thumbnail)
280	            : event.data.pic?.FullSizePicture
281	            ? this.helperService.buildPublicUrl(event.data.pic.FullSizePicture)
282	            : null;
283	        }
284	      },
285	    };
286	
287	    // Detail Cell Renderer
288	    this.customDetailCellRenderer = 'myDetailCellRenderer';
289	    console.log('[[DEBUG]] ItemLibraryComponent ngOnInit START');
290	
291	    // Update viewport meta tag
292	    this.metaService.updateTag({ name: 'viewport', content: 'width=device-width, initial-scale=1' },'name=viewport'
293	    );
294	
295	    const backgroundCard = getComputedStyle(document.body)
296	      .getPropertyValue('--background-card')
297	      .trim();
298	
299	    this.darkMode = backgroundCard;
300	
301	    if (backgroundCard === 'white') {
302	      this.gridClass = 'ag-theme-alpine';
303	    } else if (backgroundCard === '#1a202e') {
304	      this.gridClass = 'ag-theme-alpine-dark';
305	    }
306	
307	    this.fillOperation = (fillOperationParams) => {
308	      const { column, values } = fillOperationParams;
309	      const targetValue = values[0];
310	      const colId = column.colId;
311	
312	      for (let i = 0; i < this.rowData.length; i++) {
313	        const cell = this.rowData[i][colId];
314	
315	        if (!cell) continue;
316	
317	        const matches =
318	          cell.title === targetValue ||
319	          cell.RFQGroup_name === targetValue ||
320	          cell.data === targetValue;
321	
322	        if (matches) {
323	          if (cell.data) {
324	            this.findMGfromArray(cell, this.rowData);
325	            return { title: cell.data };
326	          }
327	          return cell;
328	        }
329	      }
330	
331	      return targetValue;
332	    };
333	
334	
335	    this.itemLibraryViewsInit$ = forkJoin({
336	      views: this.itemService.getUserGridViews({ grid_id: 'itemLibrary' }).pipe(catchError(() => of([]))),
337	      def: this.itemService.getGridDefaultView({ grid_id: 'itemLibrary' }).pipe(catchError(() => of(null)))
338	    }).pipe(
339	      tap(({ views, def }) => this.applyItemLibraryViewListFromApi(views, def)),
340	      shareReplay(1)
341	    );
342	    this.itemLibraryViewsInit$.subscribe({ error: (err) => console.error('[ItemLibraryComponent] itemLibraryViewsInit$ failed:', err) });
343	  }
