1083	    function monthToComparableNumber(date) {
1084	
1085	      if (date === undefined || date === null || date.length !== 10) {
1086	        return date.length;
1087	      }
1088	      var yearNumber = date.substring(6, 10);
1089	      var dayNumber = date.substring(3, 5);
1090	      var monthNumber = date.substring(0, 2);
1091	      var result = yearNumber * 10000 + monthNumber * 100 + dayNumber;
1092	      return result;
1093	    }
1094	
1095	
1096	    date1 = formatDate(date1)
1097	
1098	    date2 = formatDate(date2)
1099	
1100	    var date1Number = monthToComparableNumber(date1);
1101	    var date2Number = monthToComparableNumber(date2);
1102	    if (date1Number === null && date2Number === null) {
1103	      return 0;
1104	    }
1105	    if (date1Number === null) {
1106	      return -1;
1107	    }
1108	    if (date2Number === null) {
1109	      return 1;
1110	    }
