429	  customizeGrid(colHeaders) {
430	
431	    function percentFormatter(params) {
432	      if (params.value) {
433	        return formatNumber(params.value) + '%';
434	      }
435	    }
436	
437	    function currencyFormatter(params) {
438	      if (params.value) {
439	        return '$' + formatNumber(params.value);
440	      }
441	    }
442	
443	    function formatNumber(number) {
444	      return Number.parseFloat(number)
445	        .toFixed(2)
446	        .toString()
447	        .replace(/(\d)(?=(\d{3})+(?!\d))/g, "$1,");
448	    }
449	
450	    for (let col of colHeaders) {
451	
452	      col.hide = col.hide === "true" ? true : false;
453	      col.rowGroup = col.rowGroup === "true" ? true : false;
454	      col.rowDrag = col.rowDrag === "true" ? true : false;
455	
456	      col.tooltipField = col.field;
457	
458	      if (col.children && col.children.length > 0) {
459	
460	        col.marryChildren = true;
461	
