892	    function formatDate(input) {
893	      if (input == null) return ''
894	      if (input.includes("-")) {
895	        var datePart = input.match(/\d+/g),
896	          year = datePart[0].substring(), // get only two digits
897	          month = datePart[1], day = datePart[2];
898	        return month + '/' + day + '/' + year;
899	      } else {
900	        return input
901	      }
902	    }
903	
904	    function monthToComparableNumber(date) {
905	
906	      if (date === undefined || date === null || date.length !== 10) {
907	        return date.length;
908	      }
909	      var yearNumber = date.substring(6, 10);
910	      var dayNumber = date.substring(3, 5);
911	      var monthNumber = date.substring(0, 2);
912	      var result = yearNumber * 10000 + monthNumber * 100 + dayNumber;
913	      return result;
914	    }
915	
916	
917	    date1 = formatDate(date1)
918	
919	    date2 = formatDate(date2)
920	
921	    var date1Number = monthToComparableNumber(date1);
922	    var date2Number = monthToComparableNumber(date2);
923	    if (date1Number === null && date2Number === null) {
924	      return 0;
925	    }
926	    if (date1Number === null) {
927	      return -1;
928	    }
929	    if (date2Number === null) {
930	      return 1;
931	    }
932	    return date1Number - date2Number;
